Deque데크는 앞과 뒤에서 삽입, 삭제를 할 수 있는 자료구조임.이중 연결 리스트를 이용해서 데크를 구현할 수 있음.#include &amp;lt;iostream&amp;gt;using namespace std;typedef struct Qnode{ int data; struct Qnode* llink; struct Qnode* rlink;} Qnode;typedef struct PointQ { Qnode* front, *rear;} PointQ;template &amp;lt;class T&amp;gt;class Deque {private : int q_size=0; PointQ* DQ = new PointQ; public : Deque() { DQ-&amp;gt;front=NULL; DQ-&amp;gt;rear=NULL; } bool empty() { if(DQ-&amp;gt;front == NULL ) { return true; } else return false; } void push_front(const T&amp;amp; val) { Qnode* newNode = new Qnode; newNode-&amp;gt;data=val; newNode-&amp;gt;llink=NULL; newNode-&amp;gt;rlink=NULL; if(empty()) { DQ-&amp;gt;front=newNode; DQ-&amp;gt;rear=newNode; } else { newNode-&amp;gt;rlink=DQ-&amp;gt;front; DQ-&amp;gt;front-&amp;gt;llink = newNode; DQ-&amp;gt;front=newNode; } q_size++; } void push_back(const T&amp;amp; val) { Qnode* newNode = new Qnode; newNode-&amp;gt;data=val; newNode-&amp;gt;llink=NULL; newNode-&amp;gt;rlink=NULL; if(empty()) { DQ-&amp;gt;front=newNode; DQ-&amp;gt;rear=newNode; } else { newNode-&amp;gt;llink=DQ-&amp;gt;rear; DQ-&amp;gt;rear-&amp;gt;rlink = newNode; DQ-&amp;gt;rear=newNode; } q_size++; } void pop_front() { if(empty()) { cout &amp;lt;&amp;lt; &quot;Queue Empty!!&quot; &amp;lt;&amp;lt; &#39;
&#39;; } else { Qnode* dNode = DQ-&amp;gt;front; if(dNode-&amp;gt;rlink == NULL) { DQ-&amp;gt;front = NULL; DQ-&amp;gt;rear = NULL; } else { DQ-&amp;gt;front=dNode-&amp;gt;rlink; DQ-&amp;gt;front-&amp;gt;llink=NULL; } delete dNode; q_size--; } } void pop_back() { if(empty()) { cout &amp;lt;&amp;lt; &quot;Queue Empty!!&quot; &amp;lt;&amp;lt; &#39;
&#39;; } else { Qnode* dNode = DQ-&amp;gt;rear; if(dNode-&amp;gt;llink == NULL) { DQ-&amp;gt;front = NULL; DQ-&amp;gt;rear = NULL; } else { DQ-&amp;gt;rear=dNode-&amp;gt;llink; DQ-&amp;gt;rear-&amp;gt;rlink=NULL; } delete dNode; q_size--; } } int size() { if(empty()) { return 0; } else return q_size; } int front() { if(empty()) { return -1; } else { return DQ-&amp;gt;front-&amp;gt;data; } } int back() { if(empty()) { return -1; } else { return DQ-&amp;gt;rear-&amp;gt;data; } } void printDQ() { Qnode* pNode = DQ-&amp;gt;front; cout &amp;lt;&amp;lt; &quot;Node : [&quot;; while(pNode) { cout &amp;lt;&amp;lt; &quot; &quot; &amp;lt;&amp;lt; pNode-&amp;gt;data; pNode=pNode-&amp;gt;rlink; } cout &amp;lt;&amp;lt; &quot; ] 
&quot;; } ~Deque() { delete DQ; }};

